mapper.select:
SELECT r.id, CONCAT(cm.brand_name, ' ', cm.model_name) AS vehicleInfo, COALESCE(u.real_name, u.nickname, u.username) AS userName, r.rating, r.content, r.images, CASE WHEN r.images IS NOT NULL AND r.images != '' THEN TRUE ELSE FALSE END AS hasImage, r.create_time AS createTime, r.status, r.order_id AS orderId FROM review r LEFT JOIN `order` o ON r.order_id = o.id LEFT JOIN car_info c ON o.car_id = c.car_id LEFT JOIN car_models cm ON c.model_id = cm.model_id LEFT JOIN user u ON r.user_id = u.id
AND ( cm.brand_name LIKE CONCAT('%', #{query.keyword}, '%') OR cm.model_name LIKE CONCAT('%', #{query.keyword}, '%') OR r.content LIKE CONCAT('%', #{query.keyword}, '%') OR u.real_name LIKE CONCAT('%', #{query.keyword}, '%') OR u.nickname LIKE CONCAT('%', #{query.keyword}, '%') OR u.username LIKE CONCAT('%', #{query.keyword}, '%') )
AND r.rating = #{query.rating}
AND r.status = #{query.status}
AND c.car_id IS NOT NULL
AND c.car_id IS NULL
AND r.create_time >= #{query.startTime}
AND r.create_time <= #{query.endTime}
ORDER BY r.create_time DESC
